SELECT aircraft_id, SUM(flight_hours) AS total_flight_hours
FROM aircraft_operational_data
GROUP BY aircraft_id;

SELECT manufacturer_name, headquarters
FROM aircraft_manufacturers
ORDER BY manufacturer_name;

SELECT aircraft_characteristics
FROM aircraft
WHERE fuel_capacity = (SELECT MAX(fuel_capacity) FROM aircraft);

SELECT model_name
FROM aircraft_models
ORDER BY model_name ASC;

SELECT flight_hours, last_maintenance_date
FROM aircraft_operational_data
ORDER BY flight_hours DESC;
